import { Typography } from "@mui/material";


export default function PublicarNovedades() {
  return (
    <>
    <div className="container-fluid">
        <div className="row">
            <div className="col-12">
            <Typography
            component="h1" 
            variant="h4" 
            sx={{ 
              mb: 4,
              fontFamily: 'Tektur, sans-serif',
              fontWeight: 600,
              color: '#333'
            }}
          >
            Portal Novedades
          </Typography>
            </div>
        </div>

    </div>
    </>
  )
}
